class Solution:
    def getRow(self, rowIndex):
        from math import comb
        return [comb(rowIndex, k) for k in range(rowIndex + 1)]

solutions.python:
class Solution:
    def getRow(self, rowIndex):
        row = [1]
        for _ in range(rowIndex):
            for j in range(len(row) - 1, 0, -1):
                row[j] += row[j - 1]
            row.append(1)
        return row

